// ============================================================================
// PM CENTRAL BRAIN - ROUTE DISPATCHER V4.3
// ============================================================================

const input = $input.first().json;
const body = input.body || input;

const action = body.action || 'quick_action';

const context = {
  action: action,
  session_id: body.session_id || `session_${Date.now()}`,
  timestamp: new Date().toISOString(),

  genesis_data: action === 'genesis' ? {
    scope: body.scope,
    answers: body.answers,
    project_name: body.project_name,
    deadline: body.deadline,
    context_data: body.context_data || {}
  } : null,

  task_data: action === 'task_launch' ? {
    task_id: body.task_id,
    project_id: body.project_id || body.shared_memory?.project_id,
    user_message: body.chatInput || body.message,
    active_agent_id: body.activeAgentId || 'orchestrator',
    shared_memory: body.shared_memory || {},
    task_context: body.task_context || {}
  } : null,

  chat_data: action === 'quick_action' || action === 'chat' ? {
    message: body.chatInput || body.message,
    project_id: body.project_id || body.shared_memory?.project_id,
    active_agent_id: body.activeAgentId || 'orchestrator',
    image: body.image,
    shared_memory: body.shared_memory || {},
    task_context: body.task_context || {}
  } : null,

  writeback_data: action === 'write_back' ? {
    task_id: body.task_id,
    project_id: body.project_id,
    updates: body.updates,
    deliverable_url: body.deliverable_url,
    state_flags: body.state_flags
  } : null
};

return [{ json: context }];

// ============================================================================
// GENESIS HANDLER - Create Project + Tasks
// ============================================================================

const TASK_TEMPLATES = {
  meta_ads: [
    { title: 'Setup Technique & Budget CBO', description: 'Configurer la structure de campagne Meta', assignee: 'marcus', phase: 'Setup', estimated_hours: 2, context_questions: ['Budget quotidien ?', 'ROAS cible ?'], depends_on: [] },
    { title: 'Setup Tracking (Pixel/CAPI)', description: 'Installer Pixel Meta + CAPI', assignee: 'sora', phase: 'Setup', estimated_hours: 3, context_questions: ['GTM installe ?', 'Events a tracker ?'], depends_on: [] },
    { title: 'Copywriting Ads (3 variations)', description: 'Rediger 3 variations de textes', assignee: 'milo', phase: 'Production', estimated_hours: 3, context_questions: ['Ton de la marque ?', 'Offre principale ?'], depends_on: ['Setup Tracking (Pixel/CAPI)'] },
    { title: 'Generation Visuels Meta', description: 'Creer les visuels avec IA', assignee: 'milo', phase: 'Production', estimated_hours: 4, context_questions: ['Format prefere ?', 'Elements de marque ?'], depends_on: ['Setup Tracking (Pixel/CAPI)'] }
  ],
  seo: [
    { title: 'Audit Semantique & Technique', description: 'Analyser structure SEO', assignee: 'luna', phase: 'Audit', estimated_hours: 5, context_questions: ['URL du site ?', 'Concurrents ?'], depends_on: [] },
    { title: 'Recherche Keywords', description: 'Identifier mots-cles potentiel', assignee: 'luna', phase: 'Audit', estimated_hours: 3, context_questions: ['Thematiques ?', 'Zone geo ?'], depends_on: ['Audit Semantique & Technique'] },
    { title: 'Configuration GSC & GA4', description: 'Connecter Search Console', assignee: 'sora', phase: 'Setup', estimated_hours: 1, context_questions: ['Acces GSC ?'], depends_on: [] },
    { title: 'Redaction Page Pilier', description: 'Rediger contenu SEO', assignee: 'milo', phase: 'Production', estimated_hours: 4, context_questions: ['Sujet ?', 'Longueur ?'], depends_on: ['Recherche Keywords'] }
  ],
  sem: [
    { title: 'Audit Compte Google Ads', description: 'Analyser performance actuelle', assignee: 'sora', phase: 'Audit', estimated_hours: 2, context_questions: ['Acces Google Ads ?'], depends_on: [] },
    { title: 'Setup Campagne Search', description: 'Creer campagne Google Search', assignee: 'marcus', phase: 'Setup', estimated_hours: 3, context_questions: ['Budget ?', 'Zones geo ?'], depends_on: ['Audit Compte Google Ads'] },
    { title: 'Copywriting RSA', description: 'Rediger titres et descriptions', assignee: 'milo', phase: 'Production', estimated_hours: 2, context_questions: ['USP ?'], depends_on: [] }
  ],
  analytics: [
    { title: 'Plan de Taggage GA4 + GTM', description: 'Definir plan de taggage', assignee: 'sora', phase: 'Setup', estimated_hours: 4, context_questions: ['Events cles ?'], depends_on: [] },
    { title: 'Debugging Data Layer', description: 'Verifier anomalies', assignee: 'sora', phase: 'Audit', estimated_hours: 2, context_questions: ['Anomalies ?'], depends_on: ['Plan de Taggage GA4 + GTM'] },
    { title: 'Creation Dashboard', description: 'Construire tableau de bord', assignee: 'sora', phase: 'Production', estimated_hours: 3, context_questions: ['KPIs ?'], depends_on: ['Debugging Data Layer'] }
  ]
};

function calculateDueDates(tasks, deadline) {
  const phases = ['Audit', 'Setup', 'Production', 'Optimization'];
  let currentDate = new Date();
  const sortedTasks = [...tasks].sort((a, b) => phases.indexOf(a.phase) - phases.indexOf(b.phase));
  return sortedTasks.map(task => {
    while (currentDate.getDay() === 0 || currentDate.getDay() === 6) currentDate.setDate(currentDate.getDate() + 1);
    const dueDate = currentDate.toISOString().split('T')[0];
    currentDate.setDate(currentDate.getDate() + Math.ceil(task.estimated_hours / 6));
    return { ...task, due_date: dueDate, status: 'todo' };
  });
}

const context = $input.first().json;
const { scope, project_name, deadline, context_data } = context.genesis_data;

let baseTasks = TASK_TEMPLATES[scope] || [];
if (scope === 'full_scale') baseTasks = [...TASK_TEMPLATES.meta_ads, ...TASK_TEMPLATES.seo, ...TASK_TEMPLATES.sem, ...TASK_TEMPLATES.analytics];

const tasksWithDates = calculateDueDates(baseTasks, deadline);
const totalHours = tasksWithDates.reduce((sum, t) => sum + t.estimated_hours, 0);

return [{
  json: {
    action: 'genesis_complete',
    project: { name: project_name, scope, status: 'planning', current_phase: 'Audit', state_flags: { strategy_validated: false, budget_approved: false, creatives_ready: false, tracking_ready: false, ads_live: false }, metadata: context_data || {} },
    tasks: tasksWithDates,
    chat_message: `**Projet cree!** ${tasksWithDates.length} taches generees pour **${project_name}** (${totalHours}h estimees).`,
    meta: { agent_id: 'pm', action: 'genesis', tasks_count: tasksWithDates.length }
  }
}];

// TASK LAUNCH HANDLER - Prepare for Memory Read
const context = $input.first().json;
const taskData = context.task_data;

return [{
  json: {
    ...context,
    project_id_for_memory: taskData.project_id,
    active_agent_id: taskData.active_agent_id,
    user_message: taskData.user_message,
    shared_memory: taskData.shared_memory,
    task_context: taskData.task_context
  }
}];

// ============================================================================
// BUILD MEMORY CONTEXT V4.3
// ============================================================================

const originalContext = $('Task Launch Handler').first().json;
const memoryRecords = $input.all().map(item => item.json) || [];

const previousWork = memoryRecords.map(record => ({
  agent: record.agent_id,
  what_was_done: record.summary,
  key_findings: record.key_findings || [],
  deliverables: record.deliverables || [],
  recommendations: record.recommendations || [],
  timestamp: record.created_at
}));

function extractRelevantRecommendations(previousWork, currentAgent) {
  const recommendations = [];
  for (const work of previousWork) {
    if (work.recommendations && work.recommendations.length > 0) {
      const agentRecos = work.recommendations.filter(r => 
        typeof r === 'string' && r.toLowerCase().includes(currentAgent.toLowerCase())
      );
      if (agentRecos.length > 0) {
        recommendations.push({ from_agent: work.agent, recommendations: agentRecos.slice(0, 3) });
      }
    }
  }
  return recommendations.slice(0, 5);
}

const memoryContext = {
  project_summary: originalContext.shared_memory?.project_name || 'Projet en cours',
  previous_work: previousWork,
  validated_elements: {
    usp: originalContext.shared_memory?.metadata?.usp || null,
    persona: originalContext.shared_memory?.metadata?.targetPersona || null,
    competitors: originalContext.shared_memory?.metadata?.competitors || [],
    tone: originalContext.shared_memory?.metadata?.editorial_tone || 'professional'
  },
  current_state: {
    phase: originalContext.shared_memory?.current_phase || 'setup',
    flags: originalContext.shared_memory?.state_flags || {}
  },
  recommendations_for_current_task: extractRelevantRecommendations(previousWork, originalContext.active_agent_id)
};

return [{
  json: {
    user_message: originalContext.user_message,
    session_id: originalContext.session_id,
    suggested_agent_id: originalContext.active_agent_id,
    shared_memory: originalContext.shared_memory,
    task_context: originalContext.task_context,
    memory_context: memoryContext,
    previous_work_summary: previousWork.map(w => `${w.agent}: ${w.what_was_done}`).join('\n')
  }
}];

// ============================================================================
// PARSE PM AI RESPONSE & BUILD ORCHESTRATOR PAYLOAD
// ============================================================================

const originalContext = $('Build Memory Context').first().json;
const aiResponse = $input.first().json;

// Parse AI response
let pmDecision = {};
try {
  const output = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);
  const jsonMatch = output.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    pmDecision = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  pmDecision = {
    selected_agent: originalContext.suggested_agent_id || 'orchestrator',
    routing_reason: 'Fallback to suggested agent',
    context_enrichment: '',
    coherence_notes: ''
  };
}

// Build memory injection for orchestrator
const memoryInjection = originalContext.memory_context.previous_work.length > 0 ? `

## CONTEXTE PROJET (MEMOIRE COLLECTIVE)

**Projet:** ${originalContext.memory_context.project_summary}
**Phase:** ${originalContext.memory_context.current_state.phase}

### Travaux precedents:
${originalContext.memory_context.previous_work.map(w => `- **${w.agent.toUpperCase()}:** ${w.what_was_done}`).join('\n')}

### Recommandations PM:
${pmDecision.context_enrichment || 'Aucune instruction supplementaire.'}

### Coherence a respecter:
${pmDecision.coherence_notes || 'Aucune contrainte specifique.'}

### Elements valides:
- USP: ${originalContext.memory_context.validated_elements.usp || 'Non definie'}
- Persona: ${originalContext.memory_context.validated_elements.persona || 'Non defini'}
- Ton: ${originalContext.memory_context.validated_elements.tone || 'Professionnel'}
` : '';

// Build orchestrator payload
const orchestratorPayload = {
  chatInput: originalContext.user_message,
  session_id: originalContext.session_id,
  activeAgentId: pmDecision.selected_agent || originalContext.suggested_agent_id,
  shared_memory: originalContext.shared_memory,
  task_context: originalContext.task_context,
  system_instruction: memoryInjection,
  memory_context: originalContext.memory_context,
  pm_decision: pmDecision
};

return [{ json: orchestratorPayload }];

// ============================================================================
// PROCESS ORCHESTRATOR RESPONSE V4.3
// ============================================================================

const originalContext = $('Parse PM Decision').first().json;
const orchestratorResponse = $input.first().json;

const memoryContribution = orchestratorResponse.memory_contribution || null;

const writeBackData = memoryContribution ? {
  project_id: originalContext.shared_memory?.project_id,
  agent_id: orchestratorResponse.meta?.agent_id || originalContext.activeAgentId,
  task_id: originalContext.task_context?.task_id || null,
  action: memoryContribution.action || 'TASK_COMPLETED',
  summary: memoryContribution.summary || (orchestratorResponse.chat_message || '').substring(0, 200),
  key_findings: memoryContribution.key_findings || [],
  deliverables: memoryContribution.deliverables || [],
  recommendations: memoryContribution.recommendations_for_next_agent || []
} : null;

const flagsToUpdate = memoryContribution?.flags_to_update || null;

return [{
  json: {
    chat_message: orchestratorResponse.chat_message,
    ui_components: orchestratorResponse.ui_components || [],
    meta: orchestratorResponse.meta,
    write_back_data: writeBackData,
    flags_to_update: flagsToUpdate,
    has_memory_contribution: writeBackData !== null,
    project_id: originalContext.shared_memory?.project_id,
    task_id: originalContext.task_context?.task_id,
    pm_decision: originalContext.pm_decision
  }
}];

const processedResponse = $('Process Response').first().json;
const memoryWriteResult = $('Write Memory').first()?.json || null;
return [{ json: { ...processedResponse, memory_written: memoryWriteResult !== null, memory_id: memoryWriteResult?.id || null } }];

// WRITE-BACK HANDLER
const context = $input.first().json;
const { task_id, project_id, updates, deliverable_url, state_flags } = context.writeback_data;

return [{
  json: {
    action: 'write_back_complete',
    result: { success: true, task_id, project_id, updates_applied: { task_status: updates?.status || 'done', deliverable_url, state_flags_updated: state_flags || {}, completed_at: new Date().toISOString() } },
    chat_message: '**Tache mise a jour!** Livrable enregistre.',
    meta: { agent_id: 'pm', action: 'write_back', task_id }
  }
}];

// QUICK ACTION HANDLER - Prepare for memory read
const context = $input.first().json;
const chatData = context.chat_data;

return [{
  json: {
    ...context,
    project_id_for_memory: chatData.project_id,
    active_agent_id: chatData.active_agent_id,
    user_message: chatData.message,
    shared_memory: chatData.shared_memory,
    task_context: chatData.task_context,
    image: chatData.image
  }
}];

// ============================================================================
// FORMAT FINAL RESPONSE V4.3
// ============================================================================

const input = $input.first().json;

const finalResponse = {
  success: true,
  action: input.action || 'task_response',
  chat_message: input.chat_message || 'Demande traitee.',
  ui_components: input.ui_components || [],
  project: input.project || null,
  tasks: input.tasks || null,
  write_back_result: input.result || null,
  memory_updated: input.memory_written || input.has_memory_contribution || false,
  write_back: input.flags_to_update ? [{ type: 'UPDATE_STATE_FLAGS', flags: input.flags_to_update }] : [],
  meta: {
    ...input.meta,
    pm_version: 'v4.3-ai-brain',
    pm_decision: input.pm_decision || null,
    timestamp: new Date().toISOString()
  }
};

return [{ json: finalResponse }];
